// Format escalation message with inline keyboard for Telegram
const body = $json.body || $json;
const type = body.type || 'unknown';
const issueKey = body.issueKey || 'N/A';
const agent = body.agent || 'unknown';
const reason = body.reason || 'No reason provided';
const options = body.options || {};
const meetingId = body.meetingId || null;

// Generate a unique escalation ID
const escId = `${issueKey}-${Date.now()}`;

// Type-specific icon and label
const typeConfig = {
  'budget-exceeded': { icon: '[BUDGET]', label: 'Budget Exceeded' },
  'security-critical': { icon: '[SECURITY]', label: 'Security Critical' },
  'architecture-change': { icon: '[ARCH]', label: 'Architecture Change' },
  'customer-facing': { icon: '[CUSTOMER]', label: 'Customer-Facing Change' },
  'priority-override': { icon: '[PRIORITY]', label: 'Priority Override' }
};

const config = typeConfig[type] || { icon: '[ESCALATION]', label: type };

// Build the message text
let messageText = `${config.icon} *Escalation: ${config.label}*\n\n`;
messageText += `*Issue*: ${issueKey}\n`;
messageText += `*Agent*: ${agent}\n`;
messageText += `*Reason*: ${reason}\n`;

if (options.currentCost) {
  messageText += `*Current Cost*: $${options.currentCost}\n`;
}
if (options.requestedBudget) {
  messageText += `*Requested Budget*: $${options.requestedBudget}\n`;
}
if (options.affectedFiles) {
  messageText += `*Affected Files*: ${Array.isArray(options.affectedFiles) ? options.affectedFiles.join(', ') : options.affectedFiles}\n`;
}
if (options.riskLevel) {
  messageText += `*Risk Level*: ${options.riskLevel}\n`;
}
if (meetingId) {
  messageText += `*Meeting*: ${meetingId}\n`;
}

messageText += `\n*Time*: ${new Date().toISOString().replace('T', ' ').substring(0, 19)} UTC`;

// Build inline keyboard JSON for reply_markup
const replyMarkup = JSON.stringify({
  inline_keyboard: [
    [
      { text: 'Approve', callback_data: `esc_approve_${escId}` },
      { text: 'Reject', callback_data: `esc_reject_${escId}` },
      { text: 'Defer', callback_data: `esc_defer_${escId}` }
    ]
  ]
});

return [{
  json: {
    escId,
    type,
    issueKey,
    agent,
    reason,
    messageText,
    replyMarkup
  }
}];
